const input = $input.first().json;
const resumeText = String(input.text ?? '').trim();
const jobDescription = String(input.job_description ?? '').trim();
const targetRole = String(input.target_role ?? '').trim() || 'Not specified';

if (!resumeText) {
  throw new Error('No resume text was extracted. Use a text-based PDF; scanned PDFs require OCR.');
}
if (resumeText.length < 150) {
  throw new Error(`Extracted resume text is too short (${resumeText.length} characters).`);
}
if (jobDescription.length < 80) {
  throw new Error('Job description is too short for a meaningful comparison.');
}

return [{
  json: {
    ...input,
    input_valid: true,
    resume_text: resumeText,
    job_description: jobDescription,
    target_role: targetRole,
  },
}];

const data = $input.first().json;
const resume = data.resume_text.toLowerCase();
const jd = data.job_description.toLowerCase();

const groups = {
  'Python': ['python'],
  'C++': ['c++', 'cpp'],
  'MATLAB': ['matlab', 'simulink'],
  'Git': ['git', 'github', 'gitlab'],
  'n8n': ['n8n'],
  'REST API': ['rest api', 'restful', 'api integration'],
  'Webhooks': ['webhook', 'webhooks'],
  'JSON': ['json'],
  'Machine Learning': ['machine learning', 'pytorch', 'tensorflow'],
  'Data Analysis': ['data analysis', 'data analytics', 'pandas', 'numpy'],
  'SQL': ['sql', 'postgres', 'mysql'],
  'Docker': ['docker', 'container'],
  'Linux': ['linux', 'ubuntu'],
  'Cloud': ['aws', 'azure', 'gcp', 'cloud platform'],
  'RAG': ['rag', 'retrieval augmented generation', 'vector database'],
  'Robotics': ['robotics', 'ros'],
  'Signal Processing': ['signal processing', 'fft', 'filtering'],
  'PLC': ['plc', 'siemens s7', 'tia portal'],
};

const containsAny = (text, aliases) => aliases.some(alias => text.includes(alias));
const required = Object.entries(groups).filter(([, aliases]) => containsAny(jd, aliases)).map(([skill]) => skill);
const matched = required.filter(skill => containsAny(resume, groups[skill]));
const missing = required.filter(skill => !matched.includes(skill));

const keywordScore = required.length ? 70 * matched.length / required.length : 35;
const sectionTerms = ['profile', 'education', 'experience', 'projects', 'skills'];
const sectionHits = sectionTerms.filter(term => resume.includes(term)).length;
const structureScore = Math.min(15, sectionHits * 3);
const hasEmail = /[\w.+-]+@[\w.-]+\.[A-Za-z]{2,}/.test(data.resume_text);
const hasLink = resume.includes('github.com') || resume.includes('linkedin.com');
const contactScore = (hasEmail ? 5 : 0) + (hasLink ? 3 : 0);
const evidenceTerms = ['developed', 'built', 'implemented', 'analyzed', 'improved', 'created'];
const evidenceHits = evidenceTerms.reduce((sum, term) => sum + (resume.split(term).length - 1), 0);
const evidenceScore = Math.min(7, evidenceHits);
const score = Math.round(Math.min(100, keywordScore + structureScore + contactScore + evidenceScore));

const firstLine = data.resume_text.split(/\r?\n/).map(x => x.trim()).find(Boolean) || 'Not reliably detected';
const candidateName = firstLine.length <= 60 && !/[@|:/]/.test(firstLine) ? firstLine : 'Not reliably detected';

const strengths = [];
if (matched.length) strengths.push(`Documented overlap with key requirements: ${matched.slice(0, 6).join(', ')}`);
if (sectionHits >= 4) strengths.push('Clear resume structure with multiple ATS-readable sections');
if (evidenceHits >= 3) strengths.push('Uses evidence-oriented action verbs in technical bullets');
if (hasEmail && hasLink) strengths.push('Contact information and a professional project link are easy to find');
if (!strengths.length) strengths.push('The resume contains enough text for an initial structured review');

const weaknesses = [];
if (missing.length) weaknesses.push(`Not explicitly documented: ${missing.slice(0, 6).join(', ')}`);
if (!hasLink) weaknesses.push('No GitHub or LinkedIn URL was detected');
if (evidenceHits < 3) weaknesses.push('Project bullets could use more action verbs and measurable outcomes');
if (sectionHits < 4) weaknesses.push('Some common ATS sections are missing or use unusual headings');

const actions = missing.slice(0, 4).map(skill => `Add ${skill} only if you have real experience; otherwise build a small demonstrable project first`);
actions.push('Rewrite the strongest two project bullets using action + method + measurable result');
actions.push('Place the most role-relevant skills and evidence in the top half of the resume');
actions.push('Keep PDF formatting simple and verify that its text can be selected and copied');

const interviewQuestions = [
  `Explain one project that best demonstrates your fit for ${data.target_role}.`,
  'Describe how you validated your results and handled an unexpected failure.',
  'Which part of this workflow would you keep in n8n and which part would you implement in Python?',
];
if (missing.length) interviewQuestions.push(`How would you close the gap in ${missing[0]} during your first month?`);

return [{ json: {
  analysis_mode: 'mock',
  candidate_name: candidateName,
  target_role: data.target_role,
  ats_score: score,
  professional_summary: `The resume shows ${matched.length} of ${required.length} detected job-relevant skill groups. Review the score together with the documented project and experience evidence.`,
  matched_skills: matched,
  missing_skills: missing,
  strengths: strengths.slice(0, 5),
  weaknesses: weaknesses.slice(0, 5),
  recommended_actions: actions.slice(0, 7),
  interview_questions: interviewQuestions.slice(0, 5),
  disclaimer: 'Credential-free heuristic demo; not a hiring decision or validated ATS score.',
} }];

const raw = $input.first().json;
let a = raw.output ?? raw;
if (typeof a === 'string') {
  try { a = JSON.parse(a); } catch { throw new Error('Analysis output is not valid JSON.'); }
}

const list = value => Array.isArray(value) && value.length
  ? value.map(item => `- ${item}`).join('\n')
  : '- None detected';

const report = `# Resume Analysis Report

**Mode:** ${a.analysis_mode ?? 'openai'}  
**Candidate:** ${a.candidate_name ?? 'Not reliably detected'}  
**Target role:** ${a.target_role ?? 'Not specified'}  
**ATS-style score:** ${a.ats_score ?? 'N/A'}/100

## Summary

${a.professional_summary ?? ''}

## Matched skills

${list(a.matched_skills)}

## Missing or under-documented skills

${list(a.missing_skills)}

## Strengths

${list(a.strengths)}

## Weaknesses / resume gaps

${list(a.weaknesses)}

## Recommended actions

${list(a.recommended_actions)}

## Suggested interview questions

${list(a.interview_questions)}

---

*${a.disclaimer ?? 'AI-assisted heuristic review; verify all claims manually.'}*`;

return [{ json: { ...a, report_markdown: report } }];
